    uint32_t singleLoopCoreRowNum_ = 0;
    uint32_t singleCoreLoopCount_ = 0;
    uint32_t leftRow_ = 0;
    uint32_t tailCoreSingleLoopCoreRowNum_ = 0;
    uint32_t tailCoreSingleCoreLoopCount_ = 0;
    uint32_t tailCoreSingleCoreLoopTail_ = 0;
};

